import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import type { NotificationType } from '../../src/models/notification.js';
import { DEFAULT_EMAIL_PREFERENCES } from '../../src/models/user-preferences.js';

describe('PreferencesService', () => {
  let db: Database;
  let repo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repo = new PreferencesRepository(db);
    service = new PreferencesService(repo);
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should return undefined when no preferences exist', () => {
      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeUndefined();
    });

    it('should return existing preferences', () => {
      service.getOrCreatePreferences('user-1');
      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });
  });

  describe('getOrCreatePreferences', () => {
    it('should create default preferences for new user', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(
        DEFAULT_EMAIL_PREFERENCES.subscribedCategories,
      );
    });

    it('should return existing preferences without creating duplicates', () => {
      const first = service.getOrCreatePreferences('user-1');
      const second = service.getOrCreatePreferences('user-1');

      expect(first.id).toBe(second.id);
      expect(repo.count()).toBe(1);
    });

    it('should generate sequential IDs', () => {
      const p1 = service.getOrCreatePreferences('user-1');
      const p2 = service.getOrCreatePreferences('user-2');

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });
  });

  describe('updateEmailPreferences', () => {
    it('should update enabled flag', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', { enabled: false });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('immediate'); // unchanged
    });

    it('should update frequency', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', { frequency: 'daily-digest' });

      expect(updated.email.frequency).toBe('daily-digest');
      expect(updated.email.enabled).toBe(true); // unchanged
    });

    it('should update subscribed categories', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order-confirmation', 'system-alert'],
      });

      expect(updated.email.subscribedCategories).toEqual([
        'order-confirmation',
        'system-alert',
      ]);
    });

    it('should create defaults then update if no preferences exist', () => {
      const updated = service.updateEmailPreferences('user-1', { enabled: false });

      expect(updated.userId).toBe('user-1');
      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('immediate'); // default
    });

    it('should update multiple fields at once', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        enabled: true,
        frequency: 'weekly-digest',
        subscribedCategories: ['system-alert'],
      });

      expect(updated.email.enabled).toBe(true);
      expect(updated.email.frequency).toBe('weekly-digest');
      expect(updated.email.subscribedCategories).toEqual(['system-alert']);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (defaults)', () => {
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.getOrCreatePreferences('user-1');
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
    });

    it('should return false when frequency is none', () => {
      service.updateEmailPreferences('user-1', { frequency: 'none' });
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      service.updateEmailPreferences('user-1', {
        subscribedCategories: ['system-alert'],
      });
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
    });

    it('should return true for subscribed category', () => {
      service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order-confirmation', 'system-alert'],
      });
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'system-alert')).toBe(true);
    });

    it('should check all conditions together', () => {
      service.updateEmailPreferences('user-1', {
        enabled: true,
        frequency: 'daily-digest',
        subscribedCategories: ['order-confirmation'],
      });

      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'user-welcome')).toBe(false);
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.getOrCreatePreferences('user-1');
      expect(service.deletePreferences('user-1')).toBe(true);
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return false when no preferences exist', () => {
      expect(service.deletePreferences('user-1')).toBe(false);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('NotificationService with preferences', () => {
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    const db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);

    const prefsRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(prefsRepo);
    notificationService.setPreferencesService(preferencesService);

    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should send notification when user has no preferences (defaults)', async () => {
    const event: UserCreatedEvent = {
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(emailAdapter.getSentEmails()).toHaveLength(1);
    const notifications = notificationService.getNotifications();
    expect(notifications[0]?.suppressed).toBe(false);
  });

  it('should suppress notification when user has email disabled', async () => {
    preferencesService.updateEmailPreferences('user-1', { enabled: false });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(emailAdapter.getSentEmails()).toHaveLength(0);
    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.success).toBe(false);
    expect(notifications[0]?.suppressed).toBe(true);
  });

  it('should suppress notification when user unsubscribed from category', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['system-alert'],
    });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(emailAdapter.getSentEmails()).toHaveLength(0);
    const notifications = notificationService.getNotifications();
    expect(notifications[0]?.suppressed).toBe(true);
  });

  it('should send notification when user is subscribed to category', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['order-confirmation'],
    });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(emailAdapter.getSentEmails()).toHaveLength(1);
    const notifications = notificationService.getNotifications();
    expect(notifications[0]?.suppressed).toBe(false);
  });

  it('should work without preferences service (backwards compatible)', async () => {
    const plainService = new NotificationService(eventBus);
    plainService.registerAdapter(new EmailAdapter());

    const record = await plainService.send({
      channel: 'email',
      notificationType: 'system-alert',
      recipient: 'bob@example.com',
      subject: 'Alert',
      body: 'Something happened',
      metadata: { userId: 'user-1' },
    });

    expect(record.success).toBe(true);
    expect(record.suppressed).toBe(false);
  });
});
